"use client";

import { motion } from "framer-motion";
import { Modak } from "next/font/google";

const modak = Modak({ weight: "400", subsets: ["latin"] });

const text = "builds visual stories";

export default function Title() {
  return (
    <section style={{
      height: "80vh",
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      alignItems: "center",
      textAlign: "center"
    }}>

      {/* BRNK */}
      <motion.h1
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        style={{ fontSize: "64px", margin: 0, lineHeight: 1 }}
      >
        <span className={modak.className} style={{ letterSpacing: "0.4px" }}>
          B<span style={{ color: "#D24A16" }}>R</span>NK
        </span>
      </motion.h1>

      {/* SUBTITLE LETTER BY LETTER */}
      <div style={{ display: "flex", gap: "1px", marginTop: "10px" }}>
        {text.split("").map((char, i) => (
          <motion.span
            key={i}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{
              duration: 0.4,
              delay: 0.8 + i * 0.03
            }}
            style={{
              color: "#F9F4E6",
              fontSize: "32px",
              opacity: 0.7,
              letterSpacing: "2px"
            }}
          >
            {char}
          </motion.span>
        ))}
      </div>

    </section>
  );
}